import{_ as e,o as a,c as d,a1 as s}from"./chunks/framework.qq2wtA-j.js";const x=JSON.parse('{"title":"ASS 歌词转换脚本使用手册","description":"","frontmatter":{},"headers":[],"relativePath":"aegisub-automation/ass2lyric.md","filePath":"aegisub-automation/ass2lyric.md"}'),r={name:"aegisub-automation/ass2lyric.md"};function l(n,t,o,i,c,h){return a(),d("div",null,[...t[0]||(t[0]=[s(`<h1 id="ass-歌词转换脚本使用手册" tabindex="-1">ASS 歌词转换脚本使用手册 <a class="header-anchor" href="#ass-歌词转换脚本使用手册" aria-label="Permalink to &quot;ASS 歌词转换脚本使用手册&quot;">​</a></h1><p>本文档介绍三款 Aegisub 自动化脚本，用于将 ASS 格式的卡拉OK字幕文件转换为不同歌词格式（SPL、TTML）。</p><h2 id="脚本概述" tabindex="-1">脚本概述 <a class="header-anchor" href="#脚本概述" aria-label="Permalink to &quot;脚本概述&quot;">​</a></h2><h3 id="ass2spl-lua-—-ass-转-spl" tabindex="-1">ass2spl.lua — ASS 转 SPL <a class="header-anchor" href="#ass2spl-lua-—-ass-转-spl" aria-label="Permalink to &quot;ass2spl.lua — ASS 转 SPL&quot;">​</a></h3><p>将 ASS 字幕转换为 SPL（Subtitles Per Line）格式的歌词文件，适用于部分歌词播放器。</p><p><strong>下载链接：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/ass2spl.lua" target="_blank" rel="noreferrer">ass2spl.lua</a></p><h3 id="ass2ttml-lua-—-ass-转-ttml-v1" tabindex="-1">ass2ttml.lua — ASS 转 TTML（V1） <a class="header-anchor" href="#ass2ttml-lua-—-ass-转-ttml-v1" aria-label="Permalink to &quot;ass2ttml.lua — ASS 转 TTML（V1）&quot;">​</a></h3><p>将 ASS 字幕转换为 Apple Music 风格的 TTML（Timed Text Markup Language）歌词格式。</p><p><strong>下载链接：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/ass2ttml.lua" target="_blank" rel="noreferrer">ass2ttml.lua</a></p><h3 id="ass2ttml-v2-lua-—-ass-转-ttml-v2" tabindex="-1">ass2ttml.v2.lua — ASS 转 TTML（V2） <a class="header-anchor" href="#ass2ttml-v2-lua-—-ass-转-ttml-v2" aria-label="Permalink to &quot;ass2ttml.v2.lua — ASS 转 TTML（V2）&quot;">​</a></h3><p>V1 的升级版，支持多语言翻译和音译、多角色演唱者（单人对唱 / 多人和声）、和声处理等高级功能。</p><p><strong>下载链接：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/ass2ttml.v2.lua" target="_blank" rel="noreferrer">ass2ttml.v2.lua</a></p><h2 id="依赖库" tabindex="-1">依赖库 <a class="header-anchor" href="#依赖库" aria-label="Permalink to &quot;依赖库&quot;">​</a></h2><p>三个脚本均依赖 Aegisub 内置库 <code>karaskel.lua</code>。将这些脚本放入 Aegisub 的 <code>automation/autoload/</code> 目录即可使用。</p><h2 id="标记速查总表" tabindex="-1">标记速查总表 <a class="header-anchor" href="#标记速查总表" aria-label="Permalink to &quot;标记速查总表&quot;">​</a></h2><p>以下列出所有标记及其在三个脚本中的支持情况：</p><table tabindex="0"><thead><tr><th>标记</th><th>说明</th><th style="text-align:center;">ass2spl</th><th style="text-align:center;">ass2ttml</th><th style="text-align:center;">ass2ttml.v2</th></tr></thead><tbody><tr><td><code>x-role:&quot;名称&quot;</code></td><td>指定演唱者名称</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-person</code> / <code>x-person-N</code></td><td>声明单人演唱者</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-group</code> / <code>x-group-N</code></td><td>声明多人组合</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-other</code></td><td>声明&quot;其他&quot;演唱者</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-bg</code></td><td>标记背景和声行</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-chor</code></td><td>合唱/双行拆分</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-stash</code></td><td>和声行附属到指定行</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-anti</code> / <code>x-duet</code> / <code>x-solo</code> / <code>x-fade</code> / <code>x-whis</code></td><td>对唱样式标记</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-part:名称</code></td><td>段落标记</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-markXXX</code></td><td>自定义标记</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-lang:语言代码</code></td><td>指定行语言</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-fermata</code> / <code>x-fermata-N</code></td><td>延音标记</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td><code>x-replace</code></td><td>翻译行替换为罗马音</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>\\-merge</code> / <code>\\-M</code></td><td>合并音节</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>\\-text</code> / <code>\\-T</code></td><td>纯文本音节(无时间)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>\\-zero</code> / <code>\\-Z</code></td><td>零时长音节</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr></tbody></table><h2 id="标记详解" tabindex="-1">标记详解 <a class="header-anchor" href="#标记详解" aria-label="Permalink to &quot;标记详解&quot;">​</a></h2><h3 id="演唱者标记-role" tabindex="-1">演唱者标记（Role） <a class="header-anchor" href="#演唱者标记-role" aria-label="Permalink to &quot;演唱者标记（Role）&quot;">​</a></h3><p>用于在歌词中标注不同演唱者，实现角色切换显示。TTML V2 中会将不同演唱者组合分配不同的。</p><h4 id="x-role-名称" tabindex="-1">x-role:&quot;名称&quot; <a class="header-anchor" href="#x-role-名称" aria-label="Permalink to &quot;x-role:&quot;名称&quot;&quot;">​</a></h4><p>指定演唱者名称，放在 ASS 的 <strong>Actor</strong> 字段中。一行可包含多个角色名。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x-role:&quot;小明&quot; x-role:&quot;小红&quot;</span></span></code></pre></div><h4 id="x-person-x-group-x-other" tabindex="-1">x-person / x-group / x-other <a class="header-anchor" href="#x-person-x-group-x-other" aria-label="Permalink to &quot;x-person / x-group / x-other&quot;">​</a></h4><p>三个标记只能在 TTML V2 中使用，用于声明演唱者的类型和排序：</p><table tabindex="0"><thead><tr><th>标记</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td><code>x-person</code></td><td>声明该行为单人演唱</td><td><code>x-person x-role:&quot;小明&quot;</code></td></tr><tr><td><code>x-person-N</code></td><td>声明单人演唱并指定排序位置（N 为数字）</td><td><code>x-person-2</code> 表示第二个出场</td></tr><tr><td><code>x-group</code></td><td>声明该行为多人组合演唱</td><td><code>x-group x-role:&quot;小明&quot; x-role:&quot;小红&quot;</code></td></tr><tr><td><code>x-group-N</code></td><td>声明多人组合并指定排序位置</td><td><code>x-group-1</code></td></tr><tr><td><code>x-other</code></td><td>声明该行为&quot;其他&quot;演唱者（背景/伴唱）</td><td><code>x-other x-role:&quot;伴唱&quot;</code></td></tr></tbody></table><p>使用规则：</p><ul><li>一行中<strong>只能包含一种类型</strong>标记（person / group / other 三选一）</li><li><code>x-person</code> 行通常角色数量为 1，<code>x-group</code> 行通常有 2 个或以上角色</li><li><code>N</code> 参数用于控制输出中的演唱者排列顺序，数字越小越靠前</li></ul><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">x-role</th><th style="text-align:center;">x-person</th><th style="text-align:center;">x-group</th><th style="text-align:center;">x-other</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr></tbody></table><h3 id="背景和声标记-x-bg-x-chor-x-stash" tabindex="-1">背景和声标记（x-bg / x-chor / x-stash） <a class="header-anchor" href="#背景和声标记-x-bg-x-chor-x-stash" aria-label="Permalink to &quot;背景和声标记（x-bg / x-chor / x-stash）&quot;">​</a></h3><p>控制歌词中和声部分的输出形式。</p><h4 id="x-bg" tabindex="-1">x-bg <a class="header-anchor" href="#x-bg" aria-label="Permalink to &quot;x-bg&quot;">​</a></h4><p>放在 ASS 的 Actor 字段中，标记该行为<strong>背景和声行</strong>。和声行在 SPL 输出中会被圆括号 <code>()</code> 包裹，在 TTML 输出中作为单独的背景歌词行。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x-bg             → 标记当前行为和声行</span></span></code></pre></div><p><strong>注意：</strong> 一行同时包含 <code>x-bg</code> 和 <code>x-chor</code> 时有特殊含义（见 x-chor 说明）。</p><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">x-bg</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h4 id="x-chor" tabindex="-1">x-chor <a class="header-anchor" href="#x-chor" aria-label="Permalink to &quot;x-chor&quot;">​</a></h4><p>合唱标记。将一行歌词拆分为<strong>主唱行</strong>和<strong>对唱/和声行</strong>两行，适用于对唱和多声部场景。</p><p>在 TTML V2 中：</p><ul><li>仅 <code>x-chor</code>（无 <code>x-bg</code>）：生成两行相同文本，第二行自动添加 <code>x-anti</code> 标记</li><li><code>x-chor</code> + <code>x-bg</code> 同时存在：将当前行同时作为主行与背景行，合并输出</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x-chor                              → 合唱拆分</span></span>
<span class="line"><span>x-chor x-bg                         → 合唱同时为主+和声</span></span></code></pre></div><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">x-chor</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">❌</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h4 id="x-stash" tabindex="-1">x-stash <a class="header-anchor" href="#x-stash" aria-label="Permalink to &quot;x-stash&quot;">​</a></h4><p><strong>仅 TTML V2 支持。</strong> 控制背景行附属到哪个主行。</p><ul><li>不带 <code>x-stash</code>：背景和声行默认附属到<strong>上一个已收集的主行</strong></li><li>带 <code>x-stash</code>：背景和声行附属到<strong>下一个出现的 orig 行</strong></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x-bg x-stash     → 和声行将附属到后面的主行</span></span></code></pre></div><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">x-stash</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">❌</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">❌</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h3 id="样式标记-x-anti-x-duet-x-solo-x-fade-x-whis" tabindex="-1">样式标记（x-anti / x-duet / x-solo / x-fade / x-whis） <a class="header-anchor" href="#样式标记-x-anti-x-duet-x-solo-x-fade-x-whis" aria-label="Permalink to &quot;样式标记（x-anti / x-duet / x-solo / x-fade / x-whis）&quot;">​</a></h3><p>这些标记在代码中均由同一组逻辑处理，效果等价——用于将当前行标记为对唱样式，与 <code>x-chor</code> 拆分出的第二行效果一致。区分不同标记名称仅用作语义提示，方便打轴时区分演唱风格。</p><p>用法示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x-anti            → 反色显示，通常用于对唱中的&quot;答句&quot;</span></span>
<span class="line"><span>x-duet            → 语义上的对唱标记</span></span>
<span class="line"><span>x-solo            → 语义上的独唱标记</span></span>
<span class="line"><span>x-fade            → 语义上的渐隐标记</span></span>
<span class="line"><span>x-whis            → 语义上的轻声/耳语标记</span></span></code></pre></div><p>放入 Actor 字段即可生效。各样式具体视觉效果由播放器决定。</p><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">五种样式标记</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">❌</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h3 id="段落标记-x-part" tabindex="-1">段落标记（x-part） <a class="header-anchor" href="#段落标记-x-part" aria-label="Permalink to &quot;段落标记（x-part）&quot;">​</a></h3><p>标记歌词的段落类型（如 Verse、Chorus、Bridge 等）。</p><p>放在第一行的 Actor 字段中，段落标题为自定义文本：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x-part:Verse       → 段落类型为 Verse（主歌）</span></span>
<span class="line"><span>x-part:Chorus      → 段落类型为 Chorus（副歌）</span></span>
<span class="line"><span>x-part:Bridge      → 段落类型为 Bridge（桥段）</span></span></code></pre></div><p>在 TTML 输出中，不同段落会生成不同的 <code>&lt;div&gt;</code>。当段落切换且间隔超过 5 秒时，SPL 输出会自动插入空行作为段落分隔。</p><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">x-part</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h3 id="自定义标记-x-mark" tabindex="-1">自定义标记（x-mark） <a class="header-anchor" href="#自定义标记-x-mark" aria-label="Permalink to &quot;自定义标记（x-mark）&quot;">​</a></h3><p>用于在歌词中添加自定义备注标记，输出结束后会弹出对话框显示各标记所在的行号。</p><p>标记名称可以自定义，以 <code>x-mark</code> 开头：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x-markToDo         → 自定义标记 &quot;ToDo&quot;</span></span>
<span class="line"><span>x-markReview       → 自定义标记 &quot;Review&quot;</span></span></code></pre></div><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">x-mark</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h3 id="语言标记-x-lang" tabindex="-1">语言标记（x-lang） <a class="header-anchor" href="#语言标记-x-lang" aria-label="Permalink to &quot;语言标记（x-lang）&quot;">​</a></h3><p>指定当前翻译行（ts 行）或罗马音行（roma 行）的语言代码。放在对应的 ts 或 roma 行的 Actor 字段中。</p><p>TTML 文件遵循 IETF 的 BCP-47 语言代码标准。翻译行语言默认为 <code>zh-Hans</code>，音译行语言默认为原始歌词语言后追加 <code>-Latn</code>（如果原始语言为 <code>zh-Hans</code> 则默认 <code>zh-Latn-pinyin</code>，为 <code>zh-Hant</code> 则默认 <code>zh-Latn-jyutping</code>）。</p><p><strong>常用语言代码：</strong></p><table tabindex="0"><thead><tr><th>语言代码</th><th>说明</th></tr></thead><tbody><tr><td><code>zh-Hans</code></td><td>简体中文</td></tr><tr><td><code>zh-Hant</code></td><td>繁体中文（粤语同样使用）</td></tr><tr><td><code>zh-Latn-pinyin</code></td><td>中文拼音（不分繁简）</td></tr><tr><td><code>zh-Latn-jyutping</code></td><td>粤语注音</td></tr><tr><td><code>en</code></td><td>英文</td></tr><tr><td><code>ja</code></td><td>日语</td></tr><tr><td><code>ja-Latn</code></td><td>日语罗马音</td></tr><tr><td><code>ko</code></td><td>韩语</td></tr><tr><td><code>ko-Latn</code></td><td>韩语罗马音</td></tr></tbody></table><p>TTML V2 支持更丰富的语言代码校验，包括上述全部代码以及 BCP-47 标准中其他常见语言代码。</p><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">x-lang</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h3 id="延音标记-x-fermata" tabindex="-1">延音标记（x-fermata） <a class="header-anchor" href="#延音标记-x-fermata" aria-label="Permalink to &quot;延音标记（x-fermata）&quot;">​</a></h3><p><strong>仅 TTML V2 支持。</strong> 用于标记音符的延音，控制歌词行的持续时间。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x-fermata             → 默认延音</span></span>
<span class="line"><span>x-fermata-3           → 延音 3 单位</span></span></code></pre></div><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">x-fermata</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">❌</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">❌</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h3 id="替换行标记-x-replace" tabindex="-1">替换行标记（x-replace） <a class="header-anchor" href="#替换行标记-x-replace" aria-label="Permalink to &quot;替换行标记（x-replace）&quot;">​</a></h3><p>放在翻译行（ts 行）的 Actor 字段中，将该行从&quot;翻译行&quot;变更为&quot;罗马音行&quot;处理。用于某些翻译内容实际上应该作为罗马音输出的情况。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 在 ts 行的 Actor 中加入：</span></span>
<span class="line"><span>x-replace            → 该 ts 行将被视为 roma 行处理</span></span></code></pre></div><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">x-replace</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h2 id="卡拉ok内联特效标记" tabindex="-1">卡拉OK内联特效标记 <a class="header-anchor" href="#卡拉ok内联特效标记" aria-label="Permalink to &quot;卡拉OK内联特效标记&quot;">​</a></h2><p>这些标记嵌入在 Aegisub 的 <code>\\k</code> 卡拉OK标签中，控制音节的时长和行为。格式为 <code>{\\-标记名}</code>，放在音节开始处。</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><p>与 Aegisub 原生行为不同：Aegisub 中内联特效默认会持续影响后续所有音节，直到被覆盖或取消；但在这几个脚本中，内联标记<strong>仅作用于当前音节</strong>，不会影响后续音节。因此每个需要特殊处理的音节都需单独标记。</p></div><h3 id="合并音节-merge-m" tabindex="-1">合并音节（-merge / -M） <a class="header-anchor" href="#合并音节-merge-m" aria-label="Permalink to &quot;合并音节（\\-merge / \\-M）&quot;">​</a></h3><p>将当前音节与前一个音节合并，不产生新的时间戳。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{\\k10}今{\\k10\\-merge}天    → &quot;今天&quot; 合并为一个音节</span></span></code></pre></div><h3 id="纯文本音节-text-t" tabindex="-1">纯文本音节（-text / -T） <a class="header-anchor" href="#纯文本音节-text-t" aria-label="Permalink to &quot;纯文本音节（\\-text / \\-T）&quot;">​</a></h3><p>标记当前音节为纯文本，不附带时间信息。适用于念白或不需要逐字高亮的文本。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{\\k10}歌{\\k10\\-text}词     → &quot;词&quot; 不会产生时间标记</span></span></code></pre></div><h3 id="零时长音节-zero-z" tabindex="-1">零时长音节（-zero / -Z） <a class="header-anchor" href="#零时长音节-zero-z" aria-label="Permalink to &quot;零时长音节（\\-zero / \\-Z）&quot;">​</a></h3><p>将音节时长归零，脚本会自动根据前后音节和字符宽度为它计算合理的时间。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{\\k10}A{\\k10\\-zero}        → &quot;A&quot; 时长归零，由脚本自动计算</span></span></code></pre></div><p>常用于标点符号、半角引号等不需要完整时长的字符。脚本会智能检测引号方向（前引号对齐后一音节，后引号对齐前一音节）。</p><p><strong>支持情况：</strong></p><table tabindex="0"><thead><tr><th>脚本</th><th style="text-align:center;">-merge/-M</th><th style="text-align:center;">-text/-T</th><th style="text-align:center;">-zero/-Z</th></tr></thead><tbody><tr><td>ass2spl</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>ass2ttml.v2</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h2 id="ass-样式约定" tabindex="-1">ASS 样式约定 <a class="header-anchor" href="#ass-样式约定" aria-label="Permalink to &quot;ASS 样式约定&quot;">​</a></h2><p>三个脚本按 <strong>Style</strong> 字段区分行的用途：</p><table tabindex="0"><thead><tr><th>Style</th><th>用途</th><th>说明</th></tr></thead><tbody><tr><td><code>orig</code></td><td>原始歌词行</td><td>必需，歌曲的原始语言歌词</td></tr><tr><td><code>ts</code></td><td>翻译行</td><td>可选的翻译/译文，放在对应 orig 行之后</td></tr><tr><td><code>roma</code></td><td>罗马音行</td><td>可选的音译/罗马字，放在对应 orig 行之后</td></tr></tbody></table><p><strong>行的排列顺序：</strong> 每组歌词按 <code>orig</code> → <code>roma</code> → <code>ts</code> 的顺序排列，以相邻的 <code>orig</code> 行作为每个歌词组的开始。</p><hr><h2 id="ass-信息字段" tabindex="-1">ASS 信息字段 <a class="header-anchor" href="#ass-信息字段" aria-label="Permalink to &quot;ASS 信息字段&quot;">​</a></h2><p>在 Aegisub 的 <strong>脚本信息（Script Info）</strong> 中设定以下字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>Title</code></td><td>歌曲标题</td><td><code>Title: 晴天</code></td></tr><tr><td><code>Update Details</code></td><td>时间偏移量（毫秒）</td><td><code>Update Details: +500[整体提前500ms]</code></td></tr><tr><td><code>Original Script</code></td><td>原始歌词语言代码</td><td><code>Original Script: zh-Hans</code></td></tr></tbody></table><p>时间偏移支持正负值，方括号内的注释会被忽略。</p><hr><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><ol><li>将对应的 <code>.lua</code> 脚本文件放入 Aegisub 的 <code>automation/autoload/</code> 目录</li><li>重启 Aegisub，在 <strong>自动化（Automation）</strong> 菜单中找到对应脚本</li><li>按照上述标记约定，在 ASS 字幕中设置 Actor 字段和卡拉OK特效</li><li>运行脚本，选择导出路径或复制到剪贴板</li></ol><p>TTML V2 还提供了独立的<strong>配置菜单</strong>，可在运行前设置输出路径和 GitHub 账户信息。</p>`,127)])])}const g=e(r,[["render",l]]);export{x as __pageData,g as default};
